import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate sales commission?", a: "Multiply the sale amount by the commission rate. For example, a $10,000 sale at 5% earns $500 commission." },
  { q: "What is a typical sales commission rate?", a: "Rates vary widely by industry. Retail may be low single digits, while software, real estate, insurance, and high-ticket sales may use higher rates or split structures." },
  { q: "What is a commission split?", a: "A commission split divides earned commission between a salesperson, broker, agency, or team." },
  { q: "How is real estate commission calculated?", a: "Real estate commission is usually a percentage of sale price, often split between listing and buyer agents and their brokerages." },
  { q: "What is the difference between base salary and commission?", a: "Base salary is fixed pay. Commission is variable pay earned from sales or revenue generated." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

export default function CommissionCalculator() {
  useCurrencyVersion();
  const [mode, setMode] = useState<"rate" | "amount">("rate");
  const [sale, setSale] = useState(50000);
  const [rate, setRate] = useState(5);
  const [commissionAmount, setCommissionAmount] = useState(2500);
  const [split, setSplit] = useState(80);
  const [monthlySales, setMonthlySales] = useState(50000);
  const result = useMemo(() => {
    const commission = mode === "rate" ? sale * rate / 100 : commissionAmount;
    const effectiveRate = sale > 0 ? commission / sale * 100 : 0;
    const takeHome = commission * split / 100;
    const annual = monthlySales * effectiveRate / 100 * split / 100 * 12;
    return { commission, effectiveRate, takeHome, annual };
  }, [mode, sale, rate, commissionAmount, split, monthlySales]);
  const sales = [10000, 25000, 50000, 100000, 250000, 500000];
  const rates = [3, 5, 8, 10];

  return (
    <>
      <SEOHead title="Free Commission Calculator Online - Calculate Sales Commission Earnings Instantly | CalcHive" description="Free online commission calculator. Calculate commission earned from any sale amount and rate, take-home after splits and annual earnings projection instantly. 100% free, no signup required." canonical="/commission-calculator" keywords="free commission calculator, sales commission calculator free online, calculate commission free, real estate commission calculator free, commission earnings calculator free" category="Financial Calculators" breadcrumbName="Free Commission Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Commission Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate sales commission, reverse commission rate, take-home split, and annual earnings.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value as "rate" | "amount")} className={inputClass}><option value="rate">Find commission amount</option><option value="amount">Find commission rate</option></select></div><div><label className="text-sm font-semibold text-foreground block mb-2">Sale amount</label><input type="number" value={sale} onChange={(e) => setSale(Number(e.target.value))} className={inputClass} /></div>{mode === "rate" ? <div><label className="text-sm font-semibold text-foreground block mb-2">Commission rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div> : <div><label className="text-sm font-semibold text-foreground block mb-2">Commission amount</label><input type="number" value={commissionAmount} onChange={(e) => setCommissionAmount(Number(e.target.value))} className={inputClass} /></div>}<div><label className="text-sm font-semibold text-foreground block mb-2">Your split (%)</label><input type="number" value={split} onChange={(e) => setSplit(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Monthly sales projection</label><input type="number" value={monthlySales} onChange={(e) => setMonthlySales(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Commission Earned</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.commission)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Effective rate</p><p className="text-lg font-extrabold text-foreground">{result.effectiveRate.toFixed(2)}%</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Take-home after split</p><p className="text-lg font-extrabold text-foreground">{money(result.takeHome)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Annual projection</p><p className="text-lg font-extrabold text-foreground">{money(result.annual)}</p></div></div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Sales Commission for Free</h2><p className="text-muted-foreground leading-relaxed">Commission equals sale amount multiplied by commission rate. If you know the commission amount, divide it by sale amount to find the rate.</p><h2 className="text-2xl font-bold text-foreground">How Commission Rate and Sales Volume Affect Your Earnings</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Commission Earnings by Sales Volume and Rate</caption><thead className="bg-muted/60"><tr><th className="text-left py-3 px-3">Monthly Sales</th>{rates.map((r) => <th key={r} className="text-left py-3 px-3">{r}% Commission</th>)}</tr></thead><tbody className="divide-y divide-border">{sales.map((s) => <tr key={s}><td className="py-2.5 px-3 font-semibold">{money(s, 0)}</td>{rates.map((r) => <td key={r} className="py-2.5 px-3">{money(s * r / 100)}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Sales Commission Calculator for Salespeople and Agents</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/commission-calculator" headingLevel="h3" /></main>
    </>
  );
}


